import json, re

# Get the businesses with WiFi service that we identified earlier
wifi_businesses_data = locals()['var_functions.query_db:44']

# Extract state and business IDs for WiFi-enabled businesses
wifi_analysis = {}
business_states = {}

for biz in wifi_businesses_data:
    # Extract state from description  
    desc = biz.get('description', '')
    state_abbrev = None

    # US states list
    us_states = ['AL','AK','AZ','AR','CA','CO','CT','DE','FL','GA','HI','ID','IL','IN','IA','KS','KY','LA','ME','MD','MA','MI','MN','MS','MO','MT','NE','NV','NH','NJ','NM','NY','NC','ND','OH','OK','OR','PA','RI','SC','SD','TN','TX','UT','VT','VA','WA','WV','WI','WY']

    # Find state in description
    for state in us_states:
        if state in desc:
            state_abbrev = state
            break

    if state_abbrev:
        business_id = biz['business_id']
        wifi_analysis[business_id] = state_abbrev
        business_states[state_abbrev] = business_states.get(state_abbrev, 0) + 1

# Find state with most WiFi businesses
if business_states:
    top_state = max(business_states.items(), key=lambda x: x[1])
else:
    top_state = (None, 0)

result = {
    'wifi_businesses_by_state': business_states,
    'top_state': top_state,
    'business_id_to_state': wifi_analysis
}

print('__RESULT__:')
print(json.dumps(result))

